noncompliant:
// Noncompliant - switch with only 2 cases (fewer than 3)
switch (variable)
{
    case 0:
        doSomething();
        break;
    default:
        doSomethingElse();
        break;
}

// Noncompliant - switch expression with fewer than 3 cases
var foo = variable switch
{
    0 => doSomething(),
    _ => doSomethingElse(),
};

compliant:
// Compliant - use if-else instead of simple switch
if (variable == 0)
{
    doSomething();
}
else
{
    doSomethingElse();
}

// Compliant - use ternary operator
var foo = variable == 0 ? doSomething() : doSomethingElse();

// Compliant - switch with 3 or more cases
switch (variable)
{
    case 0:
        doSomething();
        break;
    case 1:
        doAnotherThing();
        break;
    default:
        doSomethingElse();
        break;
}
